type Cell = [number, number];

const toKey = ([x, y]: Cell): string => `${x},${y}`;
const fromKey = (key: string): Cell => {
  const [x, y] = key.split(",");
  return [Number(x), Number(y)];
};

export function nextGeneration(cells: Array<Cell>): Array<Cell> {
  const liveKeys = new Set(cells.map(toKey));

  const neighborCounts = new Map<string, number>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = toKey([x + dx, y + dy]);
        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
      }
    }
  }

  const result: Array<Cell> = [];
  for (const [key, count] of neighborCounts) {
    const survives = liveKeys.has(key) && count === 2;
    const isBorn = count === 3;
    if (survives || isBorn) {
      result.push(fromKey(key));
    }
  }

  return result;
}
